{"code": "import json, pandas as pd, re, numpy as np; from datetime import datetime; file_path = locals()['var_functions.query_db:2']; cpc5_file = locals()['var_functions.query_db:16']; data = json.load(open(file_path)); cpc5_symbols = set(item['symbol'] for item in json.load(open(cpc5_file))); parse_cpc = lambda s: [item['code'] for item in json.loads(s.strip())] if s.strip().startswith('[') else []; extract_year = lambda s: int(re.search(r'(\d{4})', re.sub(r'^(dated|on)\s+', '', s, flags=re.IGNORECASE)).group(1)) if re.search(r'(\d{4})', re.sub(r'^(dated|on)\s+', '', s, flags=re.IGNORECASE)) and 1900 <= int(re.search(r'(\d{4})', re.sub(r'^(dated|on)\s+', '', s, flags=re.IGNORECASE)).group(1)) <= 2030 else None; patent_data = []; 
for record in data:
    codes = parse_cpc(record['cpc'])
    year = extract_year(record['filing_date'])
    if year and codes:
        for code in codes:
            patent_data.append({'cpc_code': code, 'year': int(year)})
df = pd.DataFrame(patent_data); df['cpc_group'] = df['cpc_code'].apply(lambda x: x.split('/')[0] if '/' in x else x); df = df[df['cpc_group'].isin(cpc5_symbols)].copy(); 
yearly_counts = df.groupby(['cpc_group', 'year']).size().reset_index(name='count'); del df; min_year = int(yearly_counts['year'].min()); max_year = int(yearly_counts['year'].max()); all_years = list(range(min_year, max_year + 1)); all_groups = yearly_counts['cpc_group'].unique(); 
result_2022 = []; alpha = 0.2
for group in all_groups:
    group_data = yearly_counts[yearly_counts['cpc_group'] == group].sort_values('year')
    if len(group_data) == 0:
        continue
    years = group_data['year'].tolist()
    counts = group_data['count'].tolist()
    # Create full timeline
    full_years = list(range(min_year, max_year + 1))
    full_counts = [0] * len(full_years)
    for y, c in zip(years, counts):
        idx = y - min_year
        if 0 <= idx < len(full_counts):
            full_counts[idx] = c
    # Calculate EMA
    ema_values = []
    ema = None
    for count in full_counts:
        if ema is None:
            ema = count
        else:
            ema = alpha * count + (1 - alpha) * ema
        ema_values.append(ema)
    # Find best year
    max_ema_idx = np.argmax(ema_values)
    best_year = full_years[max_ema_idx]
    if best_year == 2022:
        result_2022.append(group)
print('__RESULT__:'); print(json.dumps({'cpc_groups_best_year_2022': sorted(result_2022), 'total_found': len(result_2022)}))"}

{"code": "import json, pandas as pd, re, numpy as np; from datetime import datetime; file_path = locals()['var_functions.query_db:2']; data = json.load(open(file_path)); parse_cpc = lambda s: [item['code'] for item in json.loads(s.strip())] if s.strip().startswith('[') else []; extract_year = lambda s: int(re.search(r'(\d{4})', re.sub(r'^(dated|on)\s+', '', s, flags=re.IGNORECASE)).group(1)) if re.search(r'(\d{4})', re.sub(r'^(dated|on)\s+', '', s, flags=re.IGNORECASE)) and 1900 <= int(re.search(r'(\d{4})', re.sub(r'^(dated|on)\s+', '', s, flags=re.IGNORECASE)).group(1)) <= 2030 else None; patent_data = []; 
for record in data:
    codes = parse_cpc(record['cpc'])
    year = extract_year(record['filing_date'])
    if year is not None and codes:
        for code in codes:
            patent_data.append({'cpc_code': code, 'year': int(year)})
df = pd.DataFrame(patent_data); df['cpc_group'] = df['cpc_code'].apply(lambda x: x.split('/')[0] if '/' in x else x); 
yearly_counts = df.groupby(['cpc_group', 'year']).size().reset_index(name='count'); 
min_year = int(yearly_counts['year'].min())
max_year = int(yearly_counts['year'].max())
# Get top 20 CPC groups by total count
total_counts = df.groupby('cpc_group').size().reset_index(name='total').sort_values('total', ascending=False)
print('__RESULT__:'); print(json.dumps({
    'year_range': {'min': min_year, 'max': max_year},
    'unique_cpc_groups': int(yearly_counts['cpc_group'].nunique()),
    'top_groups': total_counts.head(20).to_dict('records')
}))"}

