{"code": "import json, pandas as pd, re, numpy as np; from datetime import datetime

# Load data
file_path = locals()['var_functions.query_db:2']
cpc5_file = locals()['var_functions.query_db:16']

data = json.load(open(file_path))
cpc5_symbols = set(item['symbol'] for item in json.load(open(cpc5_file)))

print('Loaded {} patents and {} level 5 CPC symbols'.format(len(data), len(cpc5_symbols)))
print('Sample level 5 symbols: {}'.format(list(cpc5_symbols)[:10]))

# Parse CPC codes and extract years
def parse_cpc(s):
    try:
        if s and s.strip().startswith('['):
            return [item['code'] for item in json.loads(s.strip())]
    except:
        pass
    return []

def extract_year(s):
    try:
        if not s:
            return None
        clean = re.sub(r'^(dated|on)\s+', '', s, flags=re.IGNORECASE).strip()
        match = re.search(r'(\d{4})', clean)
        if match:
            year = int(match.group(1))
            if 1900 <= year <= 2030:
                return year
    except:
        pass
    return None

# Create mapping from CPC codes to level 5 symbols
cpc5_symbol_list = sorted(cpc5_symbols, key=len, reverse=True)

def map_to_level5(cpc_code):
    group = cpc_code.split('/')[0] if '/' in cpc_code else cpc_code
    for symbol in cpc5_symbol_list:
        if group.startswith(symbol):
            return symbol
    return None

# Collect patent data at level 5
patent_data = []
for i, record in enumerate(data):
    if i % 50000 == 0:
        print('Processing record {}/{}'.format(i, len(data)))
    codes = parse_cpc(record['cpc'])
    year = extract_year(record['filing_date'])
    if year and codes:
        for code in codes:
            level5_symbol = map_to_level5(code)
            if level5_symbol:
                patent_data.append({'cpc_level5': level5_symbol, 'year': year})

print('Extracted {} level 5 CPC entries'.format(len(patent_data)))

if len(patent_data) == 0:
    print('No patent data mapped to level 5')
    final_result = {'cpc_groups_best_year_2022': [], 'count': 0}
else:
    df = pd.DataFrame(patent_data)
    print('Level 5 CPC groups: {} entries, {} unique groups'.format(len(df), df['cpc_level5'].nunique()))

    # Get yearly counts
    yearly_counts = df.groupby(['cpc_level5', 'year']).size().reset_index(name='count')
    print('Yearly counts: {} records'.format(len(yearly_counts)))
    print('Year range: {} to {}'.format(yearly_counts['year'].min(), yearly_counts['year'].max()))

    # Calculate EMA for each group
    min_year = int(yearly_counts['year'].min())
    max_year = int(yearly_counts['year'].max())
    all_years = list(range(min_year, max_year + 1))
    alpha = 0.2
    result_2022 = []

    for group in yearly_counts['cpc_level5'].unique():
        group_data = yearly_counts[yearly_counts['cpc_level5'] == group].sort_values('year')
        years = group_data['year'].astype(int).tolist()
        counts = group_data['count'].astype(int).tolist()

        # Create full timeline with zeros for missing years
        full_counts = [0] * len(all_years)
        for y, c in zip(years, counts):
            idx = y - min_year
            if 0 <= idx < len(full_counts):
                full_counts[idx] = c

        # Calculate EMA
        ema_values = []
        ema = None
        for count in full_counts:
            if ema is None:
                ema = float(count)
            else:
                ema = alpha * count + (1 - alpha) * ema
            ema_values.append(ema)

        # Find best year
        if ema_values:
            max_ema_idx = np.argmax(ema_values)
            best_year = all_years[max_ema_idx]
            if best_year == 2022:
                result_2022.append(group)

    print('Found {} CPC level 5 groups with best year 2022'.format(len(result_2022)))
    final_result = {'cpc_groups_best_year_2022': sorted(result_2022), 'count': len(result_2022)}

print('__RESULT__:')
print(json.dumps(final_result))"}

