print(f'Sample level 5 symbols: {list(cpc5_symbols)[:10]}')

# Parse CPC codes and extract years
def parse_cpc(s):
    try:
        if s and s.strip().startswith('['):
            return [item['code'] for item in json.loads(s.strip())]
    except:
        pass
    return []

def extract_year(s):
    try:
        if not s:
            return None
        clean = re.sub(r'^(dated|on)\s+', '', s, flags=re.IGNORECASE).strip()
        match = re.search(r'(\d{4})', clean)
        if match:
            year = int(match.group(1))
            if 1900 <= year <= 2030:
                return year
    except:
        pass
    return None

# Create mapping from CPC groups to level 5 symbols
cpc5_symbol_list = sorted(cpc5_symbols, key=len, reverse=True)  # Sort by length (longest first)

def map_to_level5(cpc_code):
    """Map a CPC code to its level 5 parent symbol"""
    group = cpc_code.split('/')[0] if '/' in cpc_code else cpc_code
    for symbol in cpc5_symbol_list:
        if group.startswith(symbol):
            return symbol
    return None

# Collect patent data at level 5
patent_data = []
batch_size = 50000
for i, record in enumerate(data):
    if i % batch_size == 0:
        print(f'Processing record {i}/{len(data)}')
